// Repdox scanner PWA service worker.
//
// Deliberately hand-written rather than generated by a build plugin
// (e.g. vite-plugin-pwa) — the task's "no unnecessary dependencies"
// instruction, and the caching need here is narrow enough (make the
// scanner's app shell load offline) not to justify a new build-time
// dependency and its config surface.
//
// Strategy: runtime, stale-while-revalidate caching, NOT a build-time
// precache manifest. Vite's hashed output filenames change on every
// deploy, so a hand-maintained precache list would silently go stale;
// caching opportunistically as pages are actually visited avoids that
// entirely, at the cost of requiring one online visit to each page
// before it's available offline — which matches this feature's actual
// requirement ("before an event begins, the scanner should download...")
// rather than needing every route in the whole app cached upfront.
//
// Ticket *data* offline-ness (the manifest of valid tickets, the scan
// queue) is handled separately by IndexedDB — see
// src/lib/offlineTicketStore.ts. This service worker only makes the
// scanner's UI shell (HTML/JS/CSS) load without a network round-trip;
// it does not know anything about tickets.

const CACHE_NAME = "repdox-shell-v1";
const RUNTIME_CACHEABLE_PATHS = ["/scanner", "/ticket/"];

self.addEventListener("install", (event) => {
  self.skipWaiting();
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches.keys().then((keys) =>
      Promise.all(keys.filter((key) => key !== CACHE_NAME).map((key) => caches.delete(key))),
    ),
  );
  self.clients.claim();
});

function isCacheableRequest(request) {
  if (request.method !== "GET") return false;
  const url = new URL(request.url);
  if (url.origin !== self.location.origin) return false;
  // Never cache API calls — those must always reflect live server state
  // (or be explicitly handled by the offline sync queue, not a generic
  // HTTP cache) — caching a stale /api/tickets/* response would be worse
  // than no cache at all.
  if (url.pathname.startsWith("/api/")) return false;
  return true;
}

self.addEventListener("fetch", (event) => {
  const { request } = event;
  if (!isCacheableRequest(request)) return;

  event.respondWith(
    caches.open(CACHE_NAME).then(async (cache) => {
      const cached = await cache.match(request);

      const networkFetch = fetch(request)
        .then((response) => {
          if (response && response.status === 200) {
            cache.put(request, response.clone());
          }
          return response;
        })
        .catch(() => cached);

      // Stale-while-revalidate: serve the cached shell instantly if we
      // have one (this is what makes offline load feel identical to
      // online load), and refresh the cache in the background for next
      // time. Only block on the network when there's nothing cached yet.
      return cached || networkFetch;
    }),
  );
});
